      const openBraces = (repair.match(/\{/g) || []).length;
      const closeBraces = (repair.match(/\}/g) || []).length;
      const quotes = repair.match(/(?<!\\)"/g) || [];
      if (quotes.length % 2 !== 0) repair += '"';
