if (bullets.length === 0) {
  const noContent = { he: 'לא הצלחתי לחלץ מידע מהמאמר', ru: 'Не удалось извлечь информацию', en: 'Could not extract summary from article' };
  return [{ json: { text: `⚠️ ${noContent[language] || noContent.en}\n\n${url ? `<${url}|Link>` : ''}` } }];
}

const RLM = '\u200F';
const LRM = '\u200E';
const wrapLatin = t => t.replace(/([A-Za-z0-9]+(?:[.,:/\-][A-Za-z0-9]+)*)/g, `${LRM}$1${LRM}`);

let titleLine, bulletLines;

if (language === 'he') {
  const wt = wrapLatin(title);
  titleLine = url ? `${RLM}:brain: <${url}|${wt}>` : `${RLM}:brain: ${wt}`;
  bulletLines = bullets.map(b => `${RLM}• ${wrapLatin(b)}`);
} else if (language === 'ru') {
  titleLine = url ? `:brain: <${url}|${title}>` : `:brain: ${title}`;
  bulletLines = bullets.map(b => `• ${b}`);
} else {
  titleLine = url ? `:brain: Summary: <${url}|${title}>` : `:brain: Summary: ${title}`;
  bulletLines = bullets.map(b => `• ${b}`);
}

return [{ json: { text: [titleLine, '', ...bulletLines].join('\n') } }];
